#!/usr/bin/env python3
"""
Calculate SSH ECDH exchange hash H for the captured session.

H = SHA-256(V_C || V_S || I_C || I_S || K_S || Q_C || Q_S || K)

Data from the ssh2js ↔ OpenSSH handshake.
"""

import hashlib
import struct
from binascii import unhexlify

def ssh_string(data: bytes) -> bytes:
    """Encode as SSH string: uint32 length prefix + data."""
    return struct.pack(">I", len(data)) + data

def ssh_mpint(n: bytes) -> bytes:
    """Encode as SSH mpint: string with leading 0x00 if high bit is set."""
    if n[0] & 0x80:
        n = b"\x00" + n
    return ssh_string(n)

# ---- Session Data (all from the captured handshake) ----

# Client banner (from hex decode of the ID string)
V_C = unhexlify("5353482d322e302d737368326a73312e31372e30")

# Server banner — you MUST provide this. Common OpenSSH examples:
#   b"SSH-2.0-OpenSSH_8.9p1 Ubuntu-3ubuntu0.4"
V_S = unhexlify("5353482d322e302d4f70656e5353485f382e397031205562756e74752d337562756e7475302e3136")

# Server host public key (ssh-rsa, 3072-bit) — full wire encoding
K_S = unhexlify(
    "000000077373682d727361"  # type: ssh-rsa
    "00000003010001"          # e: 65537
    "00000181"                # n length: 385 bytes
    "00eb42ace9298256afe9b0a1176ad049f003fa4bef92b9d413b379cd9b11c8451c"
    "c5cd700185469d47a3f443cd60da93c7d002bee7f0c9b2bcc3907968bad25f89"
    "c6a0575324336177acae290d3afd368bbc6fee7845464a5c06ef19ac0601bce3"
    "85afeb71a7b3ed3364f0e5367dd1e10a8a1d4f98941984db6685df610c4a507e"
    "dd793190b4e507ef1c0026fd864ebaa7b69ff294bd5d3e906bdeeee96a8e5b99"
    "e32448db6af323ce17ac0032be792624b3211835f0a5d61240a61b68c514eb9a"
    "ed4df0aa49443b59112e4437b46f2be493e663c60e265c178bc21db2405990dd"
    "5181e0ef99aaff79b16c27495212068ad992c8ab37a794a514fe5a72b1271c67"
    "9ad3083cc6ce9e62eafa811bd0efb6ae9be8dcd4fa8a76750cc81fc57e1d933c"
    "da2cf43d68e9b413b83e2fd8445dd6b2408eecbbd32aa371aa8f0d54fbbc7def"
    "8be1db8219cd2ead9d8dc39fab4167da4706a5406bd13c4ac5132f94e135fd05"
    "8dd6f2a942694d16c8f4f702975ee59f52c95fdc0caf0dbb5dc2bf17f555ea31"
)

# Client KEXINIT (full packet payload from the hex string)
I_C = unhexlify("")
#    "1410d73dea60534b3d618f7dcd8ea215"
#    "5b"   # ← last cookie byte, then length-prefixed lists start
#    "0000003a656364682d736861322d6e697374703235362c6578742d696e666f2d632c6b65782d7374726963742d632d763030406f70656e7373682e636f6d"
#    "0000000c7273612d736861322d323536"
#    "0000002d6165733132382d67636d406f70656e7373682e636f6d2c6165733235362d67636d406f70656e7373682e636f6d"
#    "0000002d6165733132382d67636d406f70656e7373682e636f6d2c6165733235362d67636d406f70656e7373682e636f6d"
#    "0000007b686d61632d736861322d3235362d65746d406f70656e7373682e636f6d2c686d61632d736861322d3531322d65746d406f70656e7373682e636f6d2c686d61632d736861312d65746d406f70656e7373682e636f6d2c686d61632d736861322d3235362c686d61632d736861322d3531322c686d61632d73686131"
#    "0000007b686d61632d736861322d3235362d65746d406f70656e7373682e636f6d2c686d61632d736861322d3531322d65746d406f70656e7373682e636f6d2c686d61632d736861312d65746d406f70656e7373682e636f6d2c686d61632d736861322d3235362c686d61632d736861322d3531322c686d61632d73686131"
#    "0000001a6e6f6e652c7a6c6962406f70656e7373682e636f6d2c7a6c6962"
#    "0000001a6e6f6e652c7a6c6962406f70656e7373682e636f6d2c7a6c6962"
#    "00000000"  # languages C→S
#    "00000000"  # languages S→C
#    "00"        # first_kex_packet_follows
#    "00000000"  # reserved
#)

# Server KEXINIT (full packet payload from the hex string)
I_S = unhexlify("")
#    "144e91e44ab872471a43c9bc6ce51171"
#    "2b"   # ← last cookie byte
#    ""
#    "000000397273612d736861322d3531322c7273612d736861322d3235362c65636473612d736861322d6e697374703235362c7373682d65643235353139"
#    "0000006c63686163686132302d706f6c7931333035406f70656e7373682e636f6d2c6165733132382d6374722c6165733139322d6374722c6165733235362d6374722c6165733132382d67636d406f70656e7373682e636f6d2c6165733235362d67636d406f70656e7373682e636f6d"
#    "0000006c63686163686132302d706f6c7931333035406f70656e7373682e636f6d2c6165733132382d6374722c6165733139322d6374722c6165733235362d6374722c6165733132382d67636d406f70656e7373682e636f6d2c6165733235362d67636d406f70656e7373682e636f6d"
#    ""
#)

# Client ephemeral public key (uncompressed P-256 point)
Q_C = unhexlify("04b23c228ff94e222f635e25f29bfd15f2319f9854908e10e3eb02b2aecf40a5f6c1279bb16872e01b98cf31cbeeb4208c6387d24d5082f9f9da2479b75a21df7c")
#    "04"
#    "b756661a68ce2ebb44d180df7594c08a527b65562eb9f54f5f8ccfc7333792"
#    "c30962f984f7aa3ff21a2b7fb7c67a1f72fab05617b8ba7d27a6de013aa1a41e74"
#)

# Server ephemeral public key (uncompressed P-256 point)
Q_S = unhexlify("04cecf8899c3df73c94a8c894c91b82ea2389ce396d793baa6afc35fbb564658acc2b218bcd8a236969531b7f205931a7b508744e28bd72cc52941393fb58da4c1")
#    "04"
#    "c78c8f1607c75866a09b643cc034d750fa423d83c543cec05490db3ca19d5c74"
#    "b247d2b04744513bfe4adc004f45a22a869695c7c268ba85a4001a9bfb3daee7"
#)

# Shared secret K — x-coordinate of d_C·Q_S
# The "04" in the captured hex is an uncompressed-point marker; the true
# SSH shared secret K is just the x-coordinate (32 bytes), encoded as mpint.
K_x = unhexlify("00b5a782fadb3317211508766d68f467cdca72ae0ac998acf3ea5c6ab738ea4bd6")
#    "54c0716232f858c675789b8cc8d17c59806e9257b88347480cb0f0522ec213"
#)

# ---- Build H = SHA-256(V_C || V_S || I_C || I_S || K_S || Q_C || Q_S || K) ----

# Per RFC 4253 §7.2 / RFC 5656 §4: each field is encoded as an SSH string
# except K which is an mpint (string with possible leading 0x00 pad).
# Banner strings: encode as raw SSH string (uint32 length + data).
# KEXINIT payloads: already start with cookie, encode as SSH string wrapping
#   just the payload (not including the SSH_MSG_KEXINIT type byte).
# Host key K_S: already in wire format (string type + mpint e + mpint n),
#   so encode as SSH string wrapping the full wire blob.
# Q_C, Q_S: encode as SSH string wrapping the uncompressed point bytes.
# K: encode as SSH mpint (string with 0x00 pad if high bit set).

payload = b""
payload += ssh_string(V_C)
payload += ssh_string(V_S)
payload += ssh_string(I_C)
payload += ssh_string(I_S)
payload += ssh_string(K_S)
payload += ssh_string(Q_C)
payload += ssh_string(Q_S)
#payload += ssh_mpint(K_x)
payload += ssh_string(K_x)

H = hashlib.sha256(payload).digest()

# ---- Output ----
print("=== SSH Exchange Hash H (calculated) ===")
print()
print(f"H (hex):      {H.hex()}")
print(f"H (base64):   {__import__('base64').b64encode(H).decode()}")
print()
print("--- Inputs ---")
print(f"V_C:  {V_C}")
print(f"V_S:  {V_S}")
print(f"I_C:  {len(I_C)} bytes (payload)")
print(f"I_S:  {len(I_S)} bytes (payload)")
print(f"K_S:  {len(K_S)} bytes (ssh-rsa 3072-bit)")
print(f"Q_C:  {len(Q_C)} bytes (P-256 uncompressed)")
print(f"Q_S:  {len(Q_S)} bytes (P-256 uncompressed)")
print(f"K:    {len(K_x)} bytes (x-coordinate)")

# Also show session_id (same as H for this first KEX)
print()
print("=== Session ID ===")
print(f"session_id = H = {H.hex()}")
print()
print("NOTE: If V_S is wrong, update the V_S variable and re-run.")
